const __dirname = path.dirname(fileURLToPath(import.meta.url));

// The default Playwright harness boots the Go DDx server against a temp copy
// of e2e/fixtures/ so the API endpoints exercised by TC-008 (and other
// backend-dependent specs) return real data without reading the developer's
// $HOME or the repository's live .ddx/ state.

const CLI_PKG_DIR = path.resolve(__dirname, '../../..');
const FRONTEND_DIR = __dirname;
const FIXTURE_DIR = path.resolve(__dirname, 'e2e/fixtures');
const PORT = Number(process.env.DDX_E2E_PORT ?? 4174);
const BASE_URL = `https://127.0.0.1:${PORT}`;

// Build the SvelteKit frontend (so cli/internal/server/embed.go has assets to
// embed), copy the fixture workspace into a fresh temp dir, build the ddx
// binary from the cli module, and exec it from the temp dir. The temp dir has
// no .git so FindProjectRoot falls back to it, and tsnet is disabled so the
// harness has no Tailscale dependency.
const bootCommand = [
	`set -e`,
	`(cd "${FRONTEND_DIR}" && bun run build >&2)`,
	`TMP=$(mktemp -d -t ddx-e2e-XXXXXX)`,
	`cp -R "${FIXTURE_DIR}/." "$TMP/"`,
	`(cd "${CLI_PKG_DIR}" && go build -o "$TMP/ddx" .)`,
	`cd "$TMP"`,
	`DDX_OPERATOR_PROMPT_ALLOWLIST=localhost exec ./ddx server --tsnet=false --addr=127.0.0.1 --port=${PORT}`
].join(' && ');

export default defineConfig({
	webServer: {
		command: `bash -c '${bootCommand}'`,
		url: `${BASE_URL}/api/health`,
		ignoreHTTPSErrors: true,
		reuseExistingServer: !process.env.CI,
		timeout: 180_000,
		stdout: 'pipe',
		stderr: 'pipe'
	},
	use: {
		baseURL: BASE_URL,
		ignoreHTTPSErrors: true
	},
	testMatch: ['**/*.e2e.{ts,js}', 'e2e/**/*.spec.ts']
});

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';
import { readState } from '$lib/urlState';
import type { GroupBy } from './grouping';

export const ARTIFACTS_QUERY = gql`
	query Artifacts(
		$projectID: ID!
		$first: Int
		$after: String
		$mediaType: String
		$search: String
		$sort: ArtifactSort
		$staleness: String
		$phase: String
		$prefix: [String!]
	) {
		artifacts(
			projectID: $projectID
			first: $first
			after: $after
			mediaType: $mediaType
			search: $search
			sort: $sort
			staleness: $staleness
			phase: $phase
			prefix: $prefix
		) {
			edges {
				node {
					id
					path
					title
					mediaType
					staleness
				}
				cursor
				snippet
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`;

export interface ArtifactNode {
	id: string;
	path: string;
	title: string;
	mediaType: string;
	staleness: string;
}

export interface ArtifactEdge {
	node: ArtifactNode;
	cursor: string;
	snippet?: string | null;
}

export interface PageInfo {
	hasNextPage: boolean;
	endCursor: string | null;
}

export interface ArtifactConnection {
	edges: ArtifactEdge[];
	pageInfo: PageInfo;
	totalCount: number;
}

interface ArtifactsResult {
	artifacts: ArtifactConnection;
}

export const PAGE_SIZE = 50;

export const SORT_OPTIONS = [
	{ value: 'PATH', label: 'Path' },
	{ value: 'TITLE', label: 'Title' },
	{ value: 'MODIFIED', label: 'Last modified' },
	{ value: 'DEPS_COUNT', label: 'Dependency count' },
	{ value: 'ID', label: 'ID' }
] as const;

export type ArtifactSort = (typeof SORT_OPTIONS)[number]['value'];
export const DEFAULT_SORT: ArtifactSort = 'PATH';

const SORT_VALUES = new Set(SORT_OPTIONS.map((o) => o.value));

export function parseSort(raw: string | null): ArtifactSort {
	return raw && SORT_VALUES.has(raw as ArtifactSort) ? (raw as ArtifactSort) : DEFAULT_SORT;
}

export const STALENESS_OPTIONS = ['fresh', 'stale', 'missing'] as const;
export type Staleness = (typeof STALENESS_OPTIONS)[number];
const STALENESS_SET = new Set<string>(STALENESS_OPTIONS);

export function parseStaleness(raw: string | null): Staleness | null {
	return raw && STALENESS_SET.has(raw) ? (raw as Staleness) : null;
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const state = readState(url.searchParams);
	const hasGroupByParam = url.searchParams.has('groupBy');
	const mediaType = state.mediaType;
	const q = state.q;
	const groupBy: GroupBy = state.groupBy;
	const sort = parseSort(state.sort);
	const staleness = parseStaleness(state.staleness);
	const phase = state.phase;
	const prefix = state.prefix;

	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
		projectID: params.projectId,
		first: PAGE_SIZE,
		mediaType: mediaType ?? undefined,
		search: q ? q : undefined,
		sort,
		staleness: staleness ?? undefined,
		phase: phase ?? undefined,
		prefix: prefix.length > 0 ? prefix : undefined
	});
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifacts: data.artifacts,
		mediaType,
		q,
		groupBy,
		sort,
		staleness,
		phase,
		prefix,
		hasGroupByParam
	};
};

import type { PageLoad } from './$types'
